		public static List<Infrastructure.Data.Entities.Tables.BSD.ROH.OfferRequests.ArticleOfferRequestsEntity> GetFilterData(bool OpenRequestOnly, string Status, string cancelledFilter)
		{
			var dataTable = new DataTable();
			string OrderBy = "  order by  CreatedDate desc , SupplierContactName  ,ManufactuerNumber  ";
			var requestData = "";
			if(OpenRequestOnly)
			{
				if(Status is null || Status == "")
				{
					requestData = $" where RequestStatus = 0 and ongoingStatus not like '%{cancelledFilter}%' ";
				}
				else
				{
					requestData = $" where RequestStatus = 0 and ongoingStatus like '%{Status}%' ";
				}
			}
			else
			{
				if(Status.Contains(cancelledFilter))
				{
					requestData = $" where RequestStatus = 0 and ongoingStatus like '%{cancelledFilter}%' ";
				}
				else if(Status is null || Status == "")
				{
					requestData = $" where (RequestStatus = 1) OR (RequestStatus = 0 and ongoingStatus like '%{cancelledFilter}%') ";
				}
				else
				{
					requestData = $" where RequestStatus = 1 and ongoingStatus like '%{Status}%' ";
				}
			}
			using(var sqlConnection = new SqlConnection(Settings.ConnectionString))
			{
				sqlConnection.Open();
				string query = $"SELECT * FROM [ArticleOfferRequests] " + requestData + OrderBy;
				var sqlCommand = new SqlCommand(query, sqlConnection);

				DbExecution.Fill(sqlCommand, dataTable);
			}

			if(dataTable.Rows.Count > 0)
			{
				return dataTable.Rows.Cast<DataRow>().Select(x => new Infrastructure.Data.Entities.Tables.BSD.ROH.OfferRequests.ArticleOfferRequestsEntity(x)).ToList();
			}
			else
			{
				return new List<Infrastructure.Data.Entities.Tables.BSD.ROH.OfferRequests.ArticleOfferRequestsEntity>();
			}
		}
		public static Infrastructure.Data.Entities.Tables.BSD.ROH.OfferRequests.SupplierDefaultLanguageEntity GetDefaultLanguageForSupplier(int? SupplierId)
		{
			var dataTable = new DataTable();
			using(var sqlConnection = new SqlConnection(Settings.ConnectionString))
			{
				sqlConnection.Open();
				string query = @"select l.Nr,s.ID, s.Sprache from Lieferanten l join Sprachen s on l.Sprache = s.ID where l.Nr = @Nr";
				var sqlCommand = new SqlCommand(query, sqlConnection);
				sqlCommand.Parameters.AddWithValue("Nr", SupplierId ?? -1);

				DbExecution.Fill(sqlCommand, dataTable);

			}
			if(dataTable.Rows.Count > 0)
			{
				return new Infrastructure.Data.Entities.Tables.BSD.ROH.OfferRequests.SupplierDefaultLanguageEntity(dataTable.Rows[0]);
			}
			else
			{
				return null;
			}
		}
