		public static int UpdateOfferRequestEmailAttachementIDWithTransaction(List<int> ids, string attachment, SqlConnection connection, SqlTransaction transaction)
		{
			int results = 0;
			var idParameters = string.Join(", ", ids.Select((_, index) => $"@Id{index}"));
			string query = $@"UPDATE [ArticleOfferRequests] 
                      SET [attachment] = @attachment 
                      WHERE [Id] IN ({idParameters})";
			var sqlCommand = new SqlCommand(query, connection, transaction);
			for(int i = 0; i < ids.Count; i++)
			{
				sqlCommand.Parameters.AddWithValue($"@Id{i}", ids[i]);
			}
			sqlCommand.Parameters.AddWithValue("attachment", attachment == null ? (object)DBNull.Value : attachment);
			results = DbExecution.ExecuteNonQuery(sqlCommand);

			return results;
		}


